import { gsap } from "gsap";
const startGsapHomeAnimation = (containerElClass, delayShowInfoElClass) => {
  const gsapTimeline = gsap.timeline();
  gsapTimeline.fromTo(
    `.${containerElClass}`,
    { xPercent: "-100" },
    {
      xPercent: "0",
      duration: "1",
      onComplete: () => {
        gsapTimeline.fromTo(
          `.${delayShowInfoElClass}`,
          { display: "none", opacity: "0" },
          { display: "block", opacity: "1" },
          1.2
        );
      },
    }
  );
  return gsapTimeline;
};

export { startGsapHomeAnimation };
