<template>
  <div class="home">
    <!-- <router-link to="/actorslist">Actors List</router-link> -->

    <!-- <h1>This is HOME page</h1> -->
    <div class="desktop" v-if="!mobileWidth">
      <DesktopHome/>
    </div>
    <div class="mobile" v-else>
      <MobileHome/>
    </div>
  </div>
</template>

<script>
import DesktopHome from './DesktopHome';
import MobileHome from './MobileHome';
export default {
  name: "Home",
  components:{
    DesktopHome,
    MobileHome
  },
  data() {
    return {
      mobileWidth: false
    };
  },
  methods: {
    checkBrowserWidth(){
      const windowWidth = window.innerWidth;
      if(windowWidth < 1024){
        if(!this.mobileWidth){
          console.log('Smaller');
          this.mobileWidth = true;
        }else{
          return;
        }
      }else{
        if(this.mobileWidth){
          console.log('Bigger');
          this.mobileWidth = false;
        }else{
          return;
        }
      }
    }
  },
  created() {
    
  },
  mounted(){
    window.addEventListener('resize', this.checkBrowserWidth);
    this.checkBrowserWidth();
  },
  beforeDestroy() { 
    window.removeEventListener('resize', this.checkBrowserWidth); 
  },
};
</script>
<style scoped>
  .home{
    width:100%;
    height:100vh;
    min-height:800px;
    border: 2px solid red;
  }
  .desktop, .mobile{
    width:100%;
    height:100%;
    border: 2px solid blue;
  }
</style>